// Two actions that would each be blocked in enforce posture: one trips R2
// (would HOLD), one trips R3 (would terminal DENY). This demo runs both
// through Reeflex Gate, LOGS the verdict reeflex-core actually returned,
// and then lets the workflow proceed regardless -- a deliberate dry-run /
// shadow-mode pattern for rolling out a new policy pack safely before
// flipping a workflow to actually block on it.
return [
  {
    json: {
      table: 'customers',
      count: 50,
      reversibility: 'irreversible',
      blastRadius: 'broad',
      environment: 'production',
      externality: 'internal',
      wouldBe: 'require_approval (R2) - would HOLD in enforce posture'
    }
  },
  {
    json: {
      table: 'core_schema',
      count: 1,
      reversibility: 'irreversible',
      blastRadius: 'systemic',
      environment: 'production',
      externality: 'internal',
      wouldBe: 'deny (R3) - would be a terminal DENY in enforce posture'
    }
  }
];
